export function parsePurchaseSharesInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedPurchaseSharesInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 12) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 12,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      buyer: getNextAccount(),
      vault: getNextAccount(),
      vaultAuthority: getNextAccount(),
      shareMint: getNextAccount(),
      usdcMint: getNextAccount(),
      buyerUsdcTokenAccount: getNextAccount(),
      operatorSettlementTokenAccount: getNextAccount(),
      buyerShareTokenAccount: getNextAccount(),
      buyerPosition: getNextAccount(),
      shareTokenProgram: getNextAccount(),
      usdcTokenProgram: getNextAccount(),
      systemProgram: getNextAccount(),
    },
    data: getPurchaseSharesInstructionDataDecoder().decode(instruction.data),
  };
}
